#!/usr/bin/env python3

import subprocess
import sys
import os
import json
import hashlib
import argparse
from pathlib import Path
from typing import List, Dict, Optional, Set
import tempfile
import shutil
from datetime import datetime


class DependencyLockManager:
    def __init__(self, project_root: str = "."):
        self.project_root = Path(project_root).resolve()
        self.requirements_file = self.project_root / "requirements.txt"
        self.requirements_lock = self.project_root / "requirements-lock.txt"
        self.requirements_dev = self.project_root / "requirements-dev.txt"
        self.requirements_dev_lock = self.project_root / "requirements-dev-lock.txt"
        self.pyproject_toml = self.project_root / "pyproject.toml"
        self.poetry_lock = self.project_root / "poetry.lock"
        
    def detect_dependency_manager(self) -> str:
        if self.poetry_lock.exists() or self.pyproject_toml.exists():
            try:
                subprocess.run(["poetry", "--version"], 
                             capture_output=True, check=True)
                return "poetry"
            except (subprocess.CalledProcessError, FileNotFoundError):
                pass
        
        if self.requirements_file.exists():
            return "pip"
        
        return "none"
    
    def generate_pip_lock_file(self, input_file: Path, output_file: Path, 
                               python_version: Optional[str] = None):
        print(f"Generating lock file from {input_file} to {output_file}")
        
        with tempfile.TemporaryDirectory() as tmpdir:
            venv_path = Path(tmpdir) / "venv"
            
            python_cmd = python_version if python_version else sys.executable
            
            print(f"Creating temporary virtual environment...")
            subprocess.run([python_cmd, "-m", "venv", str(venv_path)], 
                         check=True)
            
            if os.name == 'nt':
                pip_cmd = str(venv_path / "Scripts" / "pip.exe")
                python_venv = str(venv_path / "Scripts" / "python.exe")
            else:
                pip_cmd = str(venv_path / "bin" / "pip")
                python_venv = str(venv_path / "bin" / "python")
            
            print("Upgrading pip...")
            subprocess.run([python_venv, "-m", "pip", "install", "--upgrade", "pip"],
                         check=True, capture_output=True)
            
            print(f"Installing dependencies from {input_file}...")
            subprocess.run([pip_cmd, "install", "-r", str(input_file)],
                         check=True)
            
            print("Generating lock file with hashes...")
            result = subprocess.run(
                [pip_cmd, "freeze", "--all"],
                capture_output=True, text=True, check=True
            )
            
            installed_packages = result.stdout.strip().split('\n')
            
            with open(output_file, 'w') as f:
                f.write(f"# Generated on {datetime.now().isoformat()}\n")
                f.write(f"# Python version: {self._get_python_version(python_venv)}\n")
                f.write(f"# Source: {input_file.name}\n")
                f.write("#\n")
                f.write("# This file is auto-generated. Do not edit manually.\n")
                f.write("# To update, run: python dependency_lock_manager.py generate\n\n")
                
                for package in installed_packages:
                    if package and not package.startswith('#'):
                        hashes = self._get_package_hashes(pip_cmd, package)
                        f.write(f"{package} \\\n")
                        for i, hash_value in enumerate(hashes):
                            if i < len(hashes) - 1:
                                f.write(f"    --hash={hash_value} \\\n")
                            else:
                                f.write(f"    --hash={hash_value}\n")
        
        print(f"Lock file generated successfully: {output_file}")
    
    def _get_python_version(self, python_cmd: str) -> str:
        result = subprocess.run([python_cmd, "--version"],
                              capture_output=True, text=True, check=True)
        return result.stdout.strip()
    
    def _get_package_hashes(self, pip_cmd: str, package_spec: str) -> List[str]:
        try:
            package_name = package_spec.split('==')[0]
            
            result = subprocess.run(
                [pip_cmd, "download", "--no-deps", package_spec],
                capture_output=True, text=True, cwd=tempfile.gettempdir()
            )
            
            hashes = []
            for line in result.stderr.split('\n'):
                if 'SHA256' in line or 'sha256' in line:
                    parts = line.split()
                    for part in parts:
                        if len(part) == 64 and all(c in '0123456789abcdef' for c in part.lower()):
                            hashes.append(f"sha256:{part}")
            
            if not hashes:
                result = subprocess.run(
                    [pip_cmd, "hash", package_spec],
                    capture_output=True, text=True
                )
                if result.returncode == 0:
                    for line in result.stdout.split('\n'):
                        if line.startswith('sha256:'):
                            hashes.append(line.strip())
            
            return hashes if hashes else [f"sha256:{'0'*64}"]
            
        except Exception as e:
            print(f"Warning: Could not get hash for {package_spec}: {e}")
            return []
    
    def install_from_lock(self, lock_file: Path, require_hashes: bool = True):
        print(f"Installing dependencies from {lock_file}")
        
        cmd = [sys.executable, "-m", "pip", "install", "-r", str(lock_file)]
        
        if require_hashes:
            cmd.append("--require-hashes")
        
        subprocess.run(cmd, check=True)
        print("Dependencies installed successfully")
    
    def verify_lock_file(self, lock_file: Path) -> bool:
        print(f"Verifying lock file: {lock_file}")
        
        if not lock_file.exists():
            print(f"Error: Lock file {lock_file} does not exist")
            return False
        
        with open(lock_file, 'r') as f:
            content = f.read()
        
        has_hashes = '--hash=' in content
        
        if not has_hashes:
            print("Warning: Lock file does not contain package hashes")
            return False
        
        lines = content.split('\n')
        packages = []
        current_package = []
        
        for line in lines:
            line = line.strip()
            if line and not line.startswith('#'):
                if line.endswith('\\'):
                    current_package.append(line[:-1].strip())
                else:
                    current_package.append(line)
                    packages.append(' '.join(current_package))
                    current_package = []
        
        print(f"Found {len(packages)} packages in lock file")
        
        hash_count = content.count('--hash=')
        print(f"Found {hash_count} package hashes")
        
        if hash_count < len(packages):
            print("Warning: Some packages may be missing hashes")
            return False
        
        print("Lock file verification passed")
        return True
    
    def poetry_lock_generate(self):
        print("Generating Poetry lock file...")
        subprocess.run(["poetry", "lock"], cwd=self.project_root, check=True)
        print("Poetry lock file generated successfully")
    
    def poetry_lock_update(self, packages: Optional[List[str]] = None):
        print("Updating Poetry lock file...")
        
        if packages:
            for package in packages:
                subprocess.run(["poetry", "update", package], 
                             cwd=self.project_root, check=True)
        else:
            subprocess.run(["poetry", "update"], 
                         cwd=self.project_root, check=True)
        
        print("Poetry lock file updated successfully")
    
    def poetry_install(self, no_dev: bool = False):
        print("Installing dependencies from Poetry lock file...")
        
        cmd = ["poetry", "install"]
        if no_dev:
            cmd.append("--no-dev")
        
        subprocess.run(cmd, cwd=self.project_root, check=True)
        print("Dependencies installed successfully")
    
    def poetry_export(self, output_file: Path, with_hashes: bool = True,
                     dev: bool = False):
        print(f"Exporting Poetry dependencies to {output_file}")
        
        cmd = ["poetry", "export", "-f", "requirements.txt", 
               "-o", str(output_file)]
        
        if with_hashes:
            cmd.append("--with-hashes")
        
        if dev:
            cmd.append("--dev")
        
        subprocess.run(cmd, cwd=self.project_root, check=True)
        print(f"Dependencies exported to {output_file}")
    
    def check_outdated(self):
        dep_manager = self.detect_dependency_manager()
        
        if dep_manager == "poetry":
            print("Checking for outdated packages (Poetry)...")
            subprocess.run(["poetry", "show", "--outdated"], 
                         cwd=self.project_root)
        elif dep_manager == "pip":
            print("Checking for outdated packages (pip)...")
            subprocess.run([sys.executable, "-m", "pip", "list", "--outdated"])
        else:
            print("No dependency manager detected")
    
    def sync_dependencies(self):
        dep_manager = self.detect_dependency_manager()
        
        if dep_manager == "poetry":
            print("Syncing Poetry dependencies...")
            subprocess.run(["poetry", "install", "--sync"], 
                         cwd=self.project_root, check=True)
        elif dep_manager == "pip":
            if self.requirements_lock.exists():
                self.install_from_lock(self.requirements_lock)
            else:
                print("No lock file found. Generate one first.")
        else:
            print("No dependency manager detected")
    
    def audit_security(self):
        print("Running security audit...")
        
        try:
            subprocess.run([sys.executable, "-m", "pip", "install", "safety"],
                         capture_output=True, check=True)
            
            subprocess.run([sys.executable, "-m", "safety", "check"])
        except subprocess.CalledProcessError:
            print("Security audit failed or safety not available")
    
    def create_requirements_template(self):
        if not self.requirements_file.exists():
            with open(self.requirements_file, 'w') as f:
                f.write("# Production dependencies\n")
                f.write("# Add your dependencies here without version pins\n")
                f.write("# Example:\n")
                f.write("# requests\n")
                f.write("# flask\n")
            print(f"Created template: {self.requirements_file}")
        
        if not self.requirements_dev.exists():
            with open(self.requirements_dev, 'w') as f:
                f.write("# Development dependencies\n")
                f.write("-r requirements.txt\n\n")
                f.write("# Add development dependencies here\n")
                f.write("# Example:\n")
                f.write("# pytest\n")
                f.write("# black\n")
                f.write("# flake8\n")
            print(f"Created template: {self.requirements_dev}")
    
    def create_pyproject_template(self):
        if not self.pyproject_toml.exists():
            template = """[tool.poetry]
name = "my-project"
version = "0.1.0"
description = "Project description"
authors = ["Your Name <you@example.com>"]

[tool.poetry.dependencies]
python = "^3.8"

[tool.poetry.dev-dependencies]
pytest = "^7.0"
black = "^22.0"
flake8 = "^5.0"

[build-system]
requires = ["poetry-core>=1.0.0"]
build-backend = "poetry.core.masonry.api"
"""
            with open(self.pyproject_toml, 'w') as f:
                f.write(template)
            print(f"Created template: {self.pyproject_toml}")


def main():
    parser = argparse.ArgumentParser(
        description="Python Dependency Lock File Manager",
        formatter_class=argparse.RawDescriptionHelpFormatter,
        epilog="""
Examples:
  # Generate lock files from requirements.txt
  python dependency_lock_manager.py generate
  
  # Install from lock file
  python dependency_lock_manager.py install
  
  # Verify lock file integrity
  python dependency_lock_manager.py verify
  
  # Check for outdated packages
  python dependency_lock_manager.py outdated
  
  # Poetry: generate lock file
  python dependency_lock_manager.py poetry-lock
  
  # Poetry: install dependencies
  python dependency_lock_manager.py poetry-install
  
  # Poetry: export to requirements.txt
  python dependency_lock_manager.py poetry-export
  
  # Security audit
  python dependency_lock_manager.py audit
  
  # Create template files
  python dependency_lock_manager.py init
        """
    )
    
    parser.add_argument("command", choices=[
        "generate", "install", "verify", "outdated", "sync", "audit",
        "poetry-lock", "poetry-update", "poetry-install", "poetry-export",
        "init"
    ], help="Command to execute")
    
    parser.add_argument("--project-root", default=".", 
                       help="Project root directory")
    parser.add_argument("--python-version", 
                       help="Python version to use for lock file generation")
    parser.add_argument("--no-hashes", action="store_true",
                       help="Don't require hashes when installing")
    parser.add_argument("--dev", action="store_true",
                       help="Include development dependencies")
    parser.add_argument("--packages", nargs="+",
                       help="Specific packages to update (Poetry)")
    
    args = parser.parse_args()
    
    manager = DependencyLockManager(args.project_root)
    
    try:
        if args.command == "generate":
            if manager.requirements_file.exists():
                manager.generate_pip_lock_file(
                    manager.requirements_file,
                    manager.requirements_lock,
                    args.python_version
                )
            
            if args.dev and manager.requirements_dev.exists():
                manager.generate_pip_lock_file(
                    manager.requirements_dev,
                    manager.requirements_dev_lock,
                    args.python_version
                )
        
        elif args.command == "install":
            lock_file = manager.requirements_dev_lock if args.dev else manager.requirements_lock
            manager.install_from_lock(lock_file, not args.no_hashes)
        
        elif args.command == "verify":
            lock_file = manager.requirements_dev_lock if args.dev else manager.requirements_lock
            success = manager.verify_lock_file(lock_file)
            sys.exit(0 if success else 1)
        
        elif args.command == "outdated":
            manager.check_outdated()
        
        elif args.command == "sync":
            manager.sync_dependencies()
        
        elif args.command == "audit":
            manager.audit_security()
        
        elif args.command == "poetry-lock":
            manager.poetry_lock_generate()
        
        elif args.command == "poetry-update":
            manager.poetry_lock_update(args.packages)
        
        elif args.command == "poetry-install":
            manager.poetry_install(not args.dev)
        
        elif args.command == "poetry-export":
            output = manager.requirements_lock
            manager.poetry_export(output, not args.no_hashes, args.dev)
        
        elif args.command == "init":
            dep_manager = manager.detect_dependency_manager()
            if dep_manager == "none":
                print("No dependency manager detected. Creating templates...")
                choice = input("Use Poetry (p) or pip (r)? [p/r]: ").lower()
                if choice == 'p':
                    manager.create_pyproject_template()
                else:
                    manager.create_requirements_template()
            else:
                print(f"Detected dependency manager: {dep_manager}")
    
    except subprocess.CalledProcessError as e:
        print(f"Error: Command failed with exit code {e.returncode}")
        sys.exit(1)
    except Exception as e:
        print(f"Error: {e}")
        sys.exit(1)


if __name__ == "__main__":
    main()